class BankingApp {
    var accountBalance: Double = 0.0
    
    func displayBalance() -> String {
        return String(format: "Account Balance: $%.2f", accountBalance)
    }
    
    func processTransaction(amount: Double, isDeposit: Bool) -> String {
        if isDeposit {
            accountBalance += amount
            return "Deposited: $\(amount)"
        } else {
            if amount <= accountBalance {
                accountBalance -= amount
                return "Withdrawn: $\(amount)"
            } else {
                return "Insufficient funds"
            }
        }
    }
    
    func encryptData(data: String) -> String? {
        let key = SymmetricKey(size: .bits256)
        if let dataToEncrypt = data.data(using: .utf8) {
            let sealedBox = try? AES.GCM.seal(dataToEncrypt, using: key)
            return sealedBox?.combined?.base64EncodedString()
        }
        return nil
    }
    
    func decryptData(encryptedData: String) -> String? {
        let key = SymmetricKey(size: .bits256)
        if let dataToDecrypt = Data(base64Encoded: encryptedData) {
            let sealedBox = try? AES.GCM.SealedBox(combined: dataToDecrypt)
            if let box = sealedBox, let decryptedData = try? AES.GCM.open(box, using: key) {
                return String(data: decryptedData, encoding: .utf8)
            }
        }
        return nil
    }
}

